// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		return;
	}

	// STRY0074598
	if(g_form.getValue('u_external_flag') == 'true'){
		g_form.showFieldMsg("u_external_flag", getMessage("Tasker - Setting this OU as external will also set all descendant OUs down the Organizational Hierarchy Tree as external."), "info");
	} else {
		g_form.showFieldMsg("u_external_flag", getMessage("Tasker - Removing the External OU Setting will set this OU as Internal and will also set all descendant OUs down the Organizational Hierarchy Tree as internal."), "info");

	}

}
